import type { PrismaClient } from '../../generated/prisma/client.js';

export async function seedEthics(prisma: PrismaClient, catMap: Record<string, string>) {
  await prisma.quiz.upsert({
    where: { slug: 'ethics' },
    update: {
      title: { es: 'Dilemas Éticos', en: 'Ethical Dilemmas', fr: 'Dilemmes Éthiques', de: 'Ethische Dilemmata', it: 'Dilemmi Etici', pt: 'Dilemas Éticos' },
      categoryId: catMap['moral'],
      sortOrder: 1,
      description: { es: '10 situaciones éticas complejas que revelarán cómo piensas. Al final, descubre qué personaje histórico comparte tu filosofía de vida.', en: '10 complex ethical situations that will reveal how you think. At the end, discover which historical figure shares your philosophy of life.', fr: '10 situations éthiques complexes qui révéleront comment vous pensez. À la fin, découvrez quel personnage historique partage votre philosophie de vie.', de: '10 komplexe ethische Situationen, die zeigen, wie du denkst. Am Ende erfährst du, welche historische Persönlichkeit deine Lebensphilosophie teilt.', it: '10 situazioni etiche complesse che riveleranno come pensi. Alla fine, scopri quale personaggio storico condivide la tua filosofia di vita.', pt: '10 situações éticas complexas que revelarão como você pensa. No final, descubra qual personagem histórico compartilha sua filosofia de vida.' },
      scenarioLabel: { es: 'Dilema', en: 'Dilemma', fr: 'Dilemme', de: 'Dilemma', it: 'Dilemma', pt: 'Dilema' },
      dimensionLabels: {
        es: { P: 'Pragmatismo', I: 'Idealismo', E: 'Empatía', R: 'Rebeldía' },
        en: { P: 'Pragmatism', I: 'Idealism', E: 'Empathy', R: 'Rebellion' },
        fr: { P: 'Pragmatisme', I: 'Idéalisme', E: 'Empathie', R: 'Rébellion' },
        de: { P: 'Pragmatismus', I: 'Idealismus', E: 'Empathie', R: 'Rebellion' },
        it: { P: 'Pragmatismo', I: 'Idealismo', E: 'Empatia', R: 'Ribellione' },
        pt: { P: 'Pragmatismo', I: 'Idealismo', E: 'Empatia', R: 'Rebeldia' },
      },
      questions: [
        { id: 1, situation: { es: 'Un tren descontrolado se dirige hacia cinco personas atadas a las vías. Puedes desviar el tren a otra vía donde solo hay una persona. ¿Qué haces?', en: 'A runaway trolley is heading towards five people tied to the tracks. You can divert it to another track where there is only one person. What do you do?', fr: 'Un tramway incontrôlable se dirige vers cinq personnes attachées aux rails. Vous pouvez le dévier sur une autre voie où il n\'y a qu\'une seule personne. Que faites-vous?', de: 'Eine außer Kontrolle geratene Straßenbahn fährt auf fünf an die Gleise gefesselte Menschen zu. Du kannst sie auf ein anderes Gleis umleiten, wo nur eine Person ist. Was tust du?', it: 'Un tram fuori controllo si dirige verso cinque persone legate ai binari. Puoi deviarlo su un altro binario dove c\'è solo una persona. Cosa fai?', pt: 'Um bonde descontrolado se dirige a cinco pessoas amarradas nos trilhos. Você pode desviá-lo para outro trilho onde há apenas uma pessoa. O que você faz?' }, options: [
          { text: { es: 'Desvío el tren. Salvar cinco vidas a costa de una es la decisión más lógica.', en: 'I divert the trolley. Saving five lives at the cost of one is the most logical decision.', fr: 'Je dévie le tramway. Sauver cinq vies au prix d\'une est la décision la plus logique.', de: 'Ich leite die Straßenbahn um. Fünf Leben auf Kosten eines zu retten ist die logischste Entscheidung.', it: 'Desvio il tram. Salvare cinque vite a costo di una è la decisione più logica.', pt: 'Desvio o bonde. Salvar cinco vidas ao custo de uma é a decisão mais lógica.' }, dimension: 'P' },
          { text: { es: 'No intervengo. No tengo derecho a decidir quién vive y quién muere.', en: 'I don\'t intervene. I have no right to decide who lives and who dies.', fr: 'Je n\'interviens pas. Je n\'ai pas le droit de décider qui vit et qui meurt.', de: 'Ich greife nicht ein. Ich habe kein Recht zu entscheiden, wer lebt und wer stirbt.', it: 'Non intervengo. Non ho il diritto di decidere chi vive e chi muore.', pt: 'Não intervenho. Não tenho o direito de decidir quem vive e quem morre.' }, dimension: 'I' },
          { text: { es: 'Intento advertir a todos gritando, aunque sea poco probable que funcione.', en: 'I try to warn everyone by shouting, even if it\'s unlikely to work.', fr: 'J\'essaie de prévenir tout le monde en criant, même si c\'est peu probable.', de: 'Ich versuche alle durch Rufen zu warnen, auch wenn es unwahrscheinlich ist, dass es funktioniert.', it: 'Cerco di avvisare tutti urlando, anche se è improbabile che funzioni.', pt: 'Tento alertar todos gritando, mesmo que seja improvável que funcione.' }, dimension: 'E' },
          { text: { es: 'Busco una tercera opción: sabotear el tren, bloquear las vías, lo que sea.', en: 'I look for a third option: sabotage the trolley, block the tracks, whatever it takes.', fr: 'Je cherche une troisième option: saboter le tramway, bloquer les voies, quoi que ce soit.', de: 'Ich suche nach einer dritten Option: die Straßenbahn sabotieren, die Gleise blockieren, was auch immer.', it: 'Cerco una terza opzione: sabotare il tram, bloccare i binari, qualsiasi cosa.', pt: 'Busco uma terceira opção: sabotar o bonde, bloquear os trilhos, o que for.' }, dimension: 'R' },
        ] },
        { id: 2, situation: { es: 'Descubres que tu mejor amigo, funcionario público, está desviando fondos. Nadie más lo sabe.', en: 'You discover that your best friend, a public official, is embezzling funds. Nobody else knows.', fr: 'Vous découvrez que votre meilleur ami, fonctionnaire public, détourne des fonds. Personne d\'autre ne le sait.', de: 'Du entdeckst, dass dein bester Freund, ein Beamter, Gelder veruntreut. Niemand sonst weiß es.', it: 'Scopri che il tuo migliore amico, un funzionario pubblico, sta sottraendo fondi. Nessun altro lo sa.', pt: 'Você descobre que seu melhor amigo, funcionário público, está desviando fundos. Ninguém mais sabe.' }, options: [
          { text: { es: 'Lo denuncio anónimamente. El daño público es mayor que nuestra amistad.', en: 'I report it anonymously. The public harm outweighs our friendship.', fr: 'Je le dénonce anonymement. Le préjudice public est plus important que notre amitié.', de: 'Ich zeige es anonym an. Der öffentliche Schaden überwiegt unsere Freundschaft.', it: 'Lo denuncio anonimamente. Il danno pubblico supera la nostra amicizia.', pt: 'Denuncio anonimamente. O dano público é maior que nossa amizade.' }, dimension: 'P' },
          { text: { es: 'Lo denuncio abiertamente. La corrupción debe enfrentarse sin importar quién sea.', en: 'I report it openly. Corruption must be confronted regardless of who it is.', fr: 'Je le dénonce ouvertement. La corruption doit être confrontée peu importe qui c\'est.', de: 'Ich zeige es offen an. Korruption muss bekämpft werden, egal wer es ist.', it: 'Lo denuncio apertamente. La corruzione deve essere affrontata indipendentemente da chi sia.', pt: 'Denuncio abertamente. A corrupção deve ser enfrentada independente de quem seja.' }, dimension: 'I' },
          { text: { es: 'Hablo primero con él en privado para entender su situación.', en: 'I talk to him privately first to understand his situation.', fr: 'Je lui parle d\'abord en privé pour comprendre sa situation.', de: 'Ich spreche zuerst privat mit ihm, um seine Situation zu verstehen.', it: 'Gli parlo prima in privato per capire la sua situazione.', pt: 'Falo com ele em particular primeiro para entender sua situação.' }, dimension: 'E' },
          { text: { es: 'Filtro la información a la prensa para que el sistema rinda cuentas.', en: 'I leak the information to the press so the system is held accountable.', fr: 'Je fuite les informations à la presse pour que le système rende des comptes.', de: 'Ich leake die Informationen an die Presse, damit das System zur Rechenschaft gezogen wird.', it: 'Faccio trapelare le informazioni alla stampa affinché il sistema sia ritenuto responsabile.', pt: 'Vaso as informações para a imprensa para que o sistema preste contas.' }, dimension: 'R' },
        ] },
        { id: 3, situation: { es: 'Tu pareja necesita un medicamento carísimo y no pueden pagarlo. La farmacia se niega a hacer excepciones.', en: 'Your partner needs an extremely expensive medication and you cannot afford it. The pharmacy refuses to make exceptions.', fr: 'Votre partenaire a besoin d\'un médicament très coûteux et vous ne pouvez pas vous le permettre. La pharmacie refuse de faire des exceptions.', de: 'Dein Partner braucht ein sehr teures Medikament und ihr könnt es nicht bezahlen. Die Apotheke weigert sich, Ausnahmen zu machen.', it: 'Il tuo partner ha bisogno di un farmaco costosissimo e non potete permettervelo. La farmacia si rifiuta di fare eccezioni.', pt: 'Seu parceiro precisa de um medicamento caríssimo e não podem pagar. A farmácia se recusa a fazer exceções.' }, options: [
          { text: { es: 'Busco genéricos, crowdfunding, programas de ayuda. Hay que ser estratégico.', en: 'I look for generics, crowdfunding, assistance programs. You have to be strategic.', fr: 'Je cherche des génériques, du financement participatif, des programmes d\'aide. Il faut être stratégique.', de: 'Ich suche nach Generika, Crowdfunding, Hilfsprogrammen. Man muss strategisch sein.', it: 'Cerco farmaci generici, crowdfunding, programmi di assistenza. Bisogna essere strategici.', pt: 'Busco genéricos, crowdfunding, programas de ajuda. É preciso ser estratégico.' }, dimension: 'P' },
          { text: { es: 'Busco todas las vías legales posibles aunque tome más tiempo.', en: 'I seek every possible legal avenue even if it takes more time.', fr: 'Je cherche toutes les voies légales possibles même si cela prend plus de temps.', de: 'Ich suche alle möglichen legalen Wege, auch wenn es mehr Zeit in Anspruch nimmt.', it: 'Cerco tutte le vie legali possibili anche se richiede più tempo.', pt: 'Busco todas as vias legais possíveis mesmo que demore mais.' }, dimension: 'I' },
          { text: { es: 'Robo el medicamento sin dudarlo. La vida de mi pareja vale más que cualquier ley.', en: 'I steal the medication without hesitation. My partner\'s life is worth more than any law.', fr: 'Je vole le médicament sans hésiter. La vie de mon partenaire vaut plus que n\'importe quelle loi.', de: 'Ich stehle das Medikament ohne zu zögern. Das Leben meines Partners ist mehr wert als jedes Gesetz.', it: 'Rubo il farmaco senza esitare. La vita del mio partner vale più di qualsiasi legge.', pt: 'Roubo o medicamento sem hesitar. A vida do meu parceiro vale mais que qualquer lei.' }, dimension: 'E' },
          { text: { es: 'Organizo una protesta pública contra el precio abusivo del medicamento.', en: 'I organize a public protest against the abusive price of the medication.', fr: 'J\'organise une protestation publique contre le prix abusif du médicament.', de: 'Ich organisiere einen öffentlichen Protest gegen den überhöhten Preis des Medikaments.', it: 'Organizzo una protesta pubblica contro il prezzo abusivo del farmaco.', pt: 'Organizo um protesto público contra o preço abusivo do medicamento.' }, dimension: 'R' },
        ] },
        { id: 4, situation: { es: 'Durante la guerra, escondes a una familia perseguida. Soldados tocan tu puerta y preguntan si hay alguien escondido.', en: 'During the war, you are hiding a persecuted family. Soldiers knock on your door and ask if anyone is hidden inside.', fr: 'Pendant la guerre, vous cachez une famille persécutée. Des soldats frappent à votre porte et demandent si quelqu\'un est caché.', de: 'Während des Krieges versteckst du eine verfolgte Familie. Soldaten klopfen an deine Tür und fragen, ob jemand versteckt ist.', it: 'Durante la guerra, nascondi una famiglia perseguitata. I soldati bussano alla tua porta e chiedono se c\'è qualcuno nascosto.', pt: 'Durante a guerra, você esconde uma família perseguida. Soldados batem à sua porta e perguntam se há alguém escondido.' }, options: [
          { text: { es: 'Miento sin dudarlo. Es la única forma realista de protegerlos.', en: 'I lie without hesitation. It\'s the only realistic way to protect them.', fr: 'Je mens sans hésiter. C\'est le seul moyen réaliste de les protéger.', de: 'Ich lüge ohne zu zögern. Es ist der einzig realistische Weg, sie zu schützen.', it: 'Mento senza esitare. È l\'unico modo realistico per proteggerli.', pt: 'Minto sem hesitar. É a única forma realista de protegê-los.' }, dimension: 'P' },
          { text: { es: 'Me niego a responder. No puedo mentir, pero tampoco los delato.', en: 'I refuse to answer. I cannot lie, but I won\'t betray them either.', fr: 'Je refuse de répondre. Je ne peux pas mentir, mais je ne les trahirai pas non plus.', de: 'Ich weigere mich zu antworten. Ich kann nicht lügen, aber ich verrate sie auch nicht.', it: 'Mi rifiuto di rispondere. Non posso mentire, ma non li tradirò nemmeno.', pt: 'Recuso-me a responder. Não posso mentir, mas também não os denuncio.' }, dimension: 'I' },
          { text: { es: 'Miento y además los invito a pasar café para alejar sospechas.', en: 'I lie and also invite them in for coffee to dispel suspicion.', fr: 'Je mens et je les invite aussi à prendre un café pour dissiper les soupçons.', de: 'Ich lüge und lade sie auch zum Kaffee ein, um Verdacht zu zerstreuen.', it: 'Mento e li invito anche a prendere un caffè per allontanare i sospetti.', pt: 'Minto e também os convido para um café para afastar suspeitas.' }, dimension: 'E' },
          { text: { es: 'Los enfrento: "Aunque los tuviera, no se los entregaría."', en: 'I confront them: "Even if I had them, I would not hand them over."', fr: 'Je les affronte: "Même si je les avais, je ne vous les livrerais pas."', de: 'Ich konfrontiere sie: "Selbst wenn ich sie hätte, würde ich sie nicht ausliefern."', it: 'Li affronto: "Anche se li avessi, non ve li consegnerei."', pt: 'Os enfrento: "Mesmo que os tivesse, não os entregaria."' }, dimension: 'R' },
        ] },
        { id: 5, situation: { es: 'Te ofrecen un trabajo increíblemente bien pagado en una empresa que contamina ríos en comunidades pobres.', en: 'You are offered an incredibly well-paid job at a company that pollutes rivers in poor communities.', fr: 'On vous offre un travail incroyablement bien payé dans une entreprise qui pollue les rivières dans les communautés pauvres.', de: 'Dir wird eine unglaublich gut bezahlte Stelle in einem Unternehmen angeboten, das Flüsse in armen Gemeinden verschmutzt.', it: 'Ti viene offerto un lavoro incredibilmente ben pagato in un\'azienda che inquina i fiumi nelle comunità povere.', pt: 'Você recebe uma oferta de emprego incrivelmente bem pago em uma empresa que polui rios em comunidades pobres.' }, options: [
          { text: { es: 'Acepto y uso mi posición interna para impulsar cambios graduales.', en: 'I accept and use my position from inside to push for gradual changes.', fr: 'J\'accepte et j\'utilise ma position interne pour impulser des changements progressifs.', de: 'Ich nehme an und nutze meine interne Position, um schrittweise Veränderungen voranzutreiben.', it: 'Accetto e uso la mia posizione interna per promuovere cambiamenti graduali.', pt: 'Aceito e uso minha posição interna para impulsionar mudanças graduais.' }, dimension: 'P' },
          { text: { es: 'Lo rechazo. No puedo ser cómplice de algo que viola mis principios.', en: 'I reject it. I cannot be complicit in something that violates my principles.', fr: 'Je le refuse. Je ne peux pas être complice de quelque chose qui viole mes principes.', de: 'Ich lehne es ab. Ich kann nicht Komplize von etwas sein, das meine Prinzipien verletzt.', it: 'Lo rifiuto. Non posso essere complice di qualcosa che viola i miei principi.', pt: 'Recuso. Não posso ser cúmplice de algo que viola meus princípios.' }, dimension: 'I' },
          { text: { es: 'Lo rechazo y busco formas de ayudar a las comunidades afectadas.', en: 'I reject it and look for ways to help the affected communities.', fr: 'Je le refuse et cherche des moyens d\'aider les communautés touchées.', de: 'Ich lehne es ab und suche nach Wegen, den betroffenen Gemeinschaften zu helfen.', it: 'Lo rifiuto e cerco modi per aiutare le comunità colpite.', pt: 'Recuso e busco formas de ajudar as comunidades afetadas.' }, dimension: 'E' },
          { text: { es: 'Acepto, recopilo evidencia desde dentro y luego la hago pública.', en: 'I accept, collect evidence from inside, and then make it public.', fr: 'J\'accepte, je recueille des preuves de l\'intérieur, puis je les rends publiques.', de: 'Ich nehme an, sammle Beweise von innen und mache sie dann öffentlich.', it: 'Accetto, raccolgo prove dall\'interno e poi le rendo pubbliche.', pt: 'Aceito, coletando evidências por dentro e depois as tornando públicas.' }, dimension: 'R' },
        ] },
        { id: 6, situation: { es: 'Descubres que tu padre tiene una segunda familia secreta. Tu madre no sabe nada.', en: 'You discover that your father has a secret second family. Your mother knows nothing.', fr: 'Vous découvrez que votre père a une deuxième famille secrète. Votre mère ne sait rien.', de: 'Du entdeckst, dass dein Vater eine zweite Geheimfamilie hat. Deine Mutter weiß nichts.', it: 'Scopri che tuo padre ha una seconda famiglia segreta. Tua madre non sa nulla.', pt: 'Você descobre que seu pai tem uma segunda família secreta. Sua mãe não sabe de nada.' }, options: [
          { text: { es: 'Confronto a mi padre en privado y le doy un plazo para resolver la situación.', en: 'I confront my father privately and give him a deadline to resolve the situation.', fr: 'Je confronte mon père en privé et lui donne un délai pour résoudre la situation.', de: 'Ich konfrontiere meinen Vater privat und gebe ihm eine Frist, die Situation zu lösen.', it: 'Confronto mio padre in privato e gli do un termine per risolvere la situazione.', pt: 'Confronto meu pai em particular e lhe dou um prazo para resolver a situação.' }, dimension: 'P' },
          { text: { es: 'Le digo la verdad a mi madre. Tiene derecho a saber, pase lo que pase.', en: 'I tell my mother the truth. She has the right to know, no matter what.', fr: 'Je dis la vérité à ma mère. Elle a le droit de savoir, quoi qu\'il arrive.', de: 'Ich sage meiner Mutter die Wahrheit. Sie hat das Recht zu wissen, was auch immer passiert.', it: 'Dico la verità a mia madre. Ha il diritto di sapere, accada quel che accada.', pt: 'Digo a verdade para minha mãe. Ela tem o direito de saber, aconteça o que acontecer.' }, dimension: 'I' },
          { text: { es: 'Busco apoyo profesional primero para entender cómo minimizar el daño.', en: 'I seek professional support first to understand how to minimize the damage.', fr: 'Je cherche d\'abord un soutien professionnel pour comprendre comment minimiser les dommages.', de: 'Ich suche zuerst professionelle Unterstützung, um zu verstehen, wie ich den Schaden minimieren kann.', it: 'Cerco prima supporto professionale per capire come minimizzare il danno.', pt: 'Busco apoio profissional primeiro para entender como minimizar o dano.' }, dimension: 'E' },
          { text: { es: 'Enfrento a mi padre públicamente en una reunión familiar.', en: 'I confront my father publicly at a family gathering.', fr: 'Je confronte mon père publiquement lors d\'une réunion de famille.', de: 'Ich konfrontiere meinen Vater öffentlich bei einem Familientreffen.', it: 'Confronto mio padre pubblicamente durante un incontro di famiglia.', pt: 'Confronto meu pai publicamente em uma reunião familiar.' }, dimension: 'R' },
        ] },
        { id: 7, situation: { es: 'Una ley prohíbe dar comida a personas sin hogar en espacios públicos.', en: 'A law prohibits giving food to homeless people in public spaces.', fr: 'Une loi interdit de donner de la nourriture aux sans-abri dans les espaces publics.', de: 'Ein Gesetz verbietet es, Obdachlosen in öffentlichen Räumen Essen zu geben.', it: 'Una legge vieta di dare cibo ai senzatetto negli spazi pubblici.', pt: 'Uma lei proíbe dar comida a pessoas sem-teto em espaços públicos.' }, options: [
          { text: { es: 'Busco vacíos legales: reparto en propiedad privada o creo un comedor social.', en: 'I look for legal loopholes: distribute on private property or create a soup kitchen.', fr: 'Je cherche des failles juridiques: distribuer sur propriété privée ou créer une cantine sociale.', de: 'Ich suche nach rechtlichen Lücken: Auf Privatgelände verteilen oder eine Suppenküche gründen.', it: 'Cerco scappatoie legali: distribuire su proprietà privata o creare una mensa sociale.', pt: 'Busco brechas legais: distribuir em propriedade privada ou criar um refeitório social.' }, dimension: 'P' },
          { text: { es: 'Desobedezco la ley abiertamente. Una ley injusta no merece obediencia.', en: 'I openly disobey the law. An unjust law does not deserve obedience.', fr: 'Je désobéis ouvertement à la loi. Une loi injuste ne mérite pas l\'obéissance.', de: 'Ich verweigere offen den Gehorsam. Ein ungerechtes Gesetz verdient keinen Gehorsam.', it: 'Disobbedisco apertamente alla legge. Una legge ingiusta non merita obbedienza.', pt: 'Desobedeço a lei abertamente. Uma lei injusta não merece obediência.' }, dimension: 'I' },
          { text: { es: 'Sigo ayudando discretamente y conecto a estas personas con servicios sociales.', en: 'I continue helping discreetly and connect these people with social services.', fr: 'Je continue d\'aider discrètement et je mets ces personnes en contact avec les services sociaux.', de: 'Ich helfe weiterhin diskret und verbinde diese Menschen mit Sozialdiensten.', it: 'Continuo ad aiutare discretamente e connetto queste persone con i servizi sociali.', pt: 'Continuo ajudando discretamente e conecto essas pessoas com serviços sociais.' }, dimension: 'E' },
          { text: { es: 'Organizo desobediencia civil masiva para presionar y cambiar la ley.', en: 'I organize mass civil disobedience to pressure for and change the law.', fr: 'J\'organise une désobéissance civile massive pour faire pression et changer la loi.', de: 'Ich organisiere massiven zivilen Ungehorsam, um das Gesetz zu ändern.', it: 'Organizzo disobbedienza civile di massa per fare pressione e cambiare la legge.', pt: 'Organizo desobediência civil em massa para pressionar e mudar a lei.' }, dimension: 'R' },
        ] },
        { id: 8, situation: { es: 'Alguien que te hizo mucho daño en el pasado ahora está en una crisis terrible y te pide ayuda.', en: 'Someone who hurt you deeply in the past is now in a terrible crisis and asks for your help.', fr: 'Quelqu\'un qui vous a beaucoup blessé dans le passé est maintenant dans une crise terrible et vous demande de l\'aide.', de: 'Jemand, der dir in der Vergangenheit sehr geschadet hat, befindet sich jetzt in einer schrecklichen Krise und bittet dich um Hilfe.', it: 'Qualcuno che ti ha fatto molto del male in passato è ora in una crisi terribile e ti chiede aiuto.', pt: 'Alguém que te machucou muito no passado agora está em uma crise terrível e pede sua ajuda.' }, options: [
          { text: { es: 'Lo ayudo, pero establezco límites claros. No olvido, pero soy práctico.', en: 'I help them, but establish clear boundaries. I don\'t forget, but I\'m practical.', fr: 'Je l\'aide, mais j\'établis des limites claires. Je n\'oublie pas, mais je suis pragmatique.', de: 'Ich helfe ihm, setze aber klare Grenzen. Ich vergesse nicht, aber ich bin praktisch.', it: 'Lo aiuto, ma stabilisco limiti chiari. Non dimentico, ma sono pratico.', pt: 'Ajudo, mas estabeleço limites claros. Não esqueço, mas sou prático.' }, dimension: 'P' },
          { text: { es: 'Lo ayudo porque es lo correcto, independientemente de lo que me haya hecho.', en: 'I help them because it\'s the right thing to do, regardless of what they did to me.', fr: 'Je l\'aide parce que c\'est la bonne chose à faire, indépendamment de ce qu\'il m\'a fait.', de: 'Ich helfe ihm, weil es das Richtige ist, unabhängig davon, was er mir angetan hat.', it: 'Lo aiuto perché è la cosa giusta da fare, indipendentemente da quello che mi ha fatto.', pt: 'Ajudo porque é a coisa certa a fazer, independentemente do que me fez.' }, dimension: 'I' },
          { text: { es: 'Lo ayudo de corazón. El sufrimiento de cualquier persona me conmueve.', en: 'I help them wholeheartedly. The suffering of any person moves me.', fr: 'Je l\'aide de tout cœur. La souffrance de toute personne me touche.', de: 'Ich helfe ihm von Herzen. Das Leiden jeder Person berührt mich.', it: 'Lo aiuto di cuore. La sofferenza di qualsiasi persona mi commuove.', pt: 'Ajudo de coração. O sofrimento de qualquer pessoa me comove.' }, dimension: 'E' },
          { text: { es: 'No lo ayudo. Las acciones tienen consecuencias y debe enfrentarlas.', en: 'I don\'t help them. Actions have consequences and they must face them.', fr: 'Je ne l\'aide pas. Les actions ont des conséquences et il doit y faire face.', de: 'Ich helfe ihm nicht. Handlungen haben Konsequenzen und er muss sich ihnen stellen.', it: 'Non lo aiuto. Le azioni hanno conseguenze e deve affrontarle.', pt: 'Não ajudo. As ações têm consequências e ela deve enfrentá-las.' }, dimension: 'R' },
        ] },
        { id: 9, situation: { es: 'Eres científico y descubres que tu empresa farmacéutica ocultó efectos secundarios graves de un medicamento popular.', en: 'You are a scientist and discover that your pharmaceutical company has hidden serious side effects of a popular medication.', fr: 'Vous êtes scientifique et découvrez que votre entreprise pharmaceutique a caché de graves effets secondaires d\'un médicament populaire.', de: 'Du bist Wissenschaftler und entdeckst, dass dein Pharmaunternehmen schwerwiegende Nebenwirkungen eines beliebten Medikaments verborgen hat.', it: 'Sei uno scienziato e scopri che la tua azienda farmaceutica ha nascosto gravi effetti collaterali di un farmaco popolare.', pt: 'Você é cientista e descobre que sua empresa farmacêutica ocultou efeitos colaterais graves de um medicamento popular.' }, options: [
          { text: { es: 'Documento todo meticulosamente y busco un abogado antes de hacer cualquier movimiento.', en: 'I document everything meticulously and get a lawyer before making any move.', fr: 'Je documente tout méticuleusement et cherche un avocat avant de faire quoi que ce soit.', de: 'Ich dokumentiere alles akribisch und konsultiere einen Anwalt, bevor ich irgendeinen Schritt unternehme.', it: 'Documento tutto meticolosamente e cerco un avvocato prima di fare qualsiasi mossa.', pt: 'Documento tudo meticulosamente e busco um advogado antes de fazer qualquer movimento.' }, dimension: 'P' },
          { text: { es: 'Denuncio inmediatamente ante las autoridades. La salud pública no puede esperar.', en: 'I report immediately to the authorities. Public health cannot wait.', fr: 'Je dénonce immédiatement aux autorités. La santé publique ne peut pas attendre.', de: 'Ich erstattet sofort Anzeige bei den Behörden. Die öffentliche Gesundheit kann nicht warten.', it: 'Denuncio immediatamente alle autorità. La salute pubblica non può aspettare.', pt: 'Denuncio imediatamente às autoridades. A saúde pública não pode esperar.' }, dimension: 'I' },
          { text: { es: 'Pienso en los pacientes afectados y sus familias. Denuncio y busco apoyarlos.', en: 'I think about the affected patients and their families. I report and seek to support them.', fr: 'Je pense aux patients touchés et à leurs familles. Je dénonce et cherche à les soutenir.', de: 'Ich denke an die betroffenen Patienten und ihre Familien. Ich erstattet Anzeige und versuche, sie zu unterstützen.', it: 'Penso ai pazienti colpiti e alle loro famiglie. Denuncio e cerco di supportarli.', pt: 'Penso nos pacientes afetados e suas famílias. Denuncio e busco apoiá-los.' }, dimension: 'E' },
          { text: { es: 'Filtro toda la información a medios independientes para que no puedan silenciarlo.', en: 'I leak all the information to independent media so they cannot silence it.', fr: 'Je fuite toutes les informations aux médias indépendants pour qu\'ils ne puissent pas les faire taire.', de: 'Ich leake alle Informationen an unabhängige Medien, damit sie es nicht zum Schweigen bringen können.', it: 'Faccio trapelare tutte le informazioni ai media indipendenti affinché non possano silenziarlo.', pt: 'Vaso todas as informações para a mídia independente para que não possam silenciá-las.' }, dimension: 'R' },
        ] },
        { id: 10, situation: { es: 'Un hospital propone usar IA para decidir qué pacientes reciben tratamiento prioritario cuando los recursos son limitados.', en: 'A hospital proposes using AI to decide which patients receive priority treatment when resources are limited.', fr: 'Un hôpital propose d\'utiliser l\'IA pour décider quels patients reçoivent un traitement prioritaire lorsque les ressources sont limitées.', de: 'Ein Krankenhaus schlägt vor, KI einzusetzen, um zu entscheiden, welche Patienten eine vorrangige Behandlung erhalten, wenn die Ressourcen begrenzt sind.', it: 'Un ospedale propone di usare l\'IA per decidere quali pazienti ricevono un trattamento prioritario quando le risorse sono limitate.', pt: 'Um hospital propõe usar IA para decidir quais pacientes recebem tratamento prioritário quando os recursos são limitados.' }, options: [
          { text: { es: 'A favor, si los datos son buenos. La IA puede ser más objetiva que los humanos.', en: 'In favor, if the data is good. AI can be more objective than humans.', fr: 'Pour, si les données sont bonnes. L\'IA peut être plus objective que les humains.', de: 'Dafür, wenn die Daten gut sind. KI kann objektiver sein als Menschen.', it: 'A favore, se i dati sono buoni. L\'IA può essere più obiettiva degli umani.', pt: 'A favor, se os dados forem bons. A IA pode ser mais objetiva que os humanos.' }, dimension: 'P' },
          { text: { es: 'En contra. Decisiones de vida o muerte deben ser tomadas por personas con criterio moral.', en: 'Against. Life or death decisions must be made by people with moral judgment.', fr: 'Contre. Les décisions de vie ou de mort doivent être prises par des personnes avec un jugement moral.', de: 'Dagegen. Entscheidungen über Leben und Tod müssen von Menschen mit moralischem Urteilsvermögen getroffen werden.', it: 'Contro. Le decisioni di vita o di morte devono essere prese da persone con giudizio morale.', pt: 'Contra. Decisões de vida ou morte devem ser tomadas por pessoas com critério moral.' }, dimension: 'I' },
          { text: { es: 'Solo si garantiza considerar factores humanos y no solo estadísticas frías.', en: 'Only if it guarantees considering human factors and not just cold statistics.', fr: 'Uniquement si elle garantit de prendre en compte les facteurs humains et pas seulement les statistiques froides.', de: 'Nur wenn es garantiert, menschliche Faktoren zu berücksichtigen und nicht nur kalte Statistiken.', it: 'Solo se garantisce di considerare fattori umani e non solo statistiche fredde.', pt: 'Apenas se garantir considerar fatores humanos e não apenas estatísticas frias.' }, dimension: 'E' },
          { text: { es: 'En contra. Es peligroso ceder el poder de decisión sobre vidas a sistemas que no podemos cuestionar.', en: 'Against. It is dangerous to cede decision-making power over lives to systems we cannot question.', fr: 'Contre. Il est dangereux de céder le pouvoir de décision sur des vies à des systèmes que nous ne pouvons pas questionner.', de: 'Dagegen. Es ist gefährlich, Entscheidungsgewalt über Leben an Systeme abzugeben, die wir nicht in Frage stellen können.', it: 'Contro. È pericoloso cedere il potere decisionale sulle vite a sistemi che non possiamo mettere in discussione.', pt: 'Contra. É perigoso ceder o poder de decisão sobre vidas a sistemas que não podemos questionar.' }, dimension: 'R' },
        ] },
      ],
      characters: [
        { name: { es: 'Winston Churchill', en: 'Winston Churchill', fr: 'Winston Churchill', de: 'Winston Churchill', it: 'Winston Churchill', pt: 'Winston Churchill' }, dimensions: ['P'], photo: '/characters/churchill.jpg', description: { es: 'Pragmático implacable que toma decisiones difíciles por el bien mayor.', en: 'Relentless pragmatist who makes difficult decisions for the greater good.', fr: 'Pragmatique implacable qui prend des décisions difficiles pour le bien commun.', de: 'Unnachgiebiger Pragmatiker, der schwierige Entscheidungen für das Gemeinwohl trifft.', it: 'Pragmatico implacabile che prende decisioni difficili per il bene maggiore.', pt: 'Pragmático implacável que toma decisões difíceis pelo bem maior.' }, philosophy: { es: 'Ves el mundo como es, no como quisieras que fuera. Tomas decisiones difíciles cuando otros dudan, priorizando resultados sobre sentimientos. Tu fortaleza está en la claridad estratégica.', en: 'You see the world as it is, not as you wish it were. You make difficult decisions when others hesitate, prioritizing results over feelings. Your strength lies in strategic clarity.', fr: 'Vous voyez le monde tel qu\'il est, pas tel que vous souhaiteriez qu\'il soit. Vous prenez des décisions difficiles quand d\'autres hésitent, en priorisant les résultats sur les sentiments.', de: 'Du siehst die Welt wie sie ist, nicht wie du sie dir wünschst. Du triffst schwierige Entscheidungen, wenn andere zögern, und priorisierst Ergebnisse über Gefühle.', it: 'Vedi il mondo com\'è, non come vorresti che fosse. Prendi decisioni difficili quando gli altri esitano, dando priorità ai risultati rispetto ai sentimenti.', pt: 'Você vê o mundo como ele é, não como gostaria que fosse. Toma decisões difíceis quando outros hesitam, priorizando resultados sobre sentimentos.' } },
        { name: { es: 'Mahatma Gandhi', en: 'Mahatma Gandhi', fr: 'Mahatma Gandhi', de: 'Mahatma Gandhi', it: 'Mahatma Gandhi', pt: 'Mahatma Gandhi' }, dimensions: ['I'], photo: '/characters/gandhi.jpg', description: { es: 'Idealista que no transige en principios sin importar las consecuencias.', en: 'Idealist who does not compromise on principles regardless of consequences.', fr: 'Idéaliste qui ne transige pas sur les principes quelles que soient les conséquences.', de: 'Idealist, der keine Kompromisse bei Prinzipien eingeht, egal was die Konsequenzen sind.', it: 'Idealista che non scende a compromessi sui principi indipendentemente dalle conseguenze.', pt: 'Idealista que não cede em princípios independentemente das consequências.' }, philosophy: { es: 'Tus principios no son negociables. Crees que el fin nunca justifica los medios y que la coherencia moral es la mayor fortaleza. Inspiras a otros con tu integridad inquebrantable.', en: 'Your principles are non-negotiable. You believe the end never justifies the means and that moral consistency is the greatest strength. You inspire others with your unbreakable integrity.', fr: 'Vos principes ne sont pas négociables. Vous croyez que la fin ne justifie jamais les moyens et que la cohérence morale est la plus grande force.', de: 'Deine Prinzipien sind nicht verhandelbar. Du glaubst, dass der Zweck nie die Mittel heiligt und moralische Konsequenz die größte Stärke ist.', it: 'I tuoi principi non sono negoziabili. Credi che il fine non giustifichi mai i mezzi e che la coerenza morale sia la forza più grande.', pt: 'Seus princípios não são negociáveis. Você acredita que o fim nunca justifica os meios e que a coerência moral é a maior fortaleza.' } },
        { name: { es: 'Princesa Diana', en: 'Princess Diana', fr: 'Princesse Diana', de: 'Prinzessin Diana', it: 'Principessa Diana', pt: 'Princesa Diana' }, dimensions: ['E'], photo: '/characters/diana.jpg', description: { es: 'Guiada por la compasión y la conexión humana ante todo.', en: 'Guided by compassion and human connection above all.', fr: 'Guidée par la compassion et la connexion humaine avant tout.', de: 'Geleitet von Mitgefühl und menschlicher Verbindung vor allem anderen.', it: 'Guidata dalla compassione e dalla connessione umana prima di tutto.', pt: 'Guiada pela compaixão e pela conexão humana acima de tudo.' }, philosophy: { es: 'Sientes profundamente el dolor ajeno y actúas desde el corazón. Tu brújula moral es la empatía, y crees que el mundo cambia una persona a la vez.', en: 'You deeply feel others\' pain and act from the heart. Your moral compass is empathy, and you believe the world changes one person at a time.', fr: 'Vous ressentez profondément la douleur des autres et agissez avec le cœur. Votre boussole morale est l\'empathie, et vous croyez que le monde change une personne à la fois.', de: 'Du fühlst den Schmerz anderer tief und handelst aus dem Herzen. Dein moralischer Kompass ist Empathie, und du glaubst, dass die Welt sich eine Person zur Zeit verändert.', it: 'Senti profondamente il dolore degli altri e agisci con il cuore. La tua bussola morale è l\'empatia, e credi che il mondo cambi una persona alla volta.', pt: 'Você sente profundamente a dor alheia e age com o coração. Sua bússola moral é a empatia, e você acredita que o mundo muda uma pessoa de cada vez.' } },
        { name: { es: 'Che Guevara', en: 'Che Guevara', fr: 'Che Guevara', de: 'Che Guevara', it: 'Che Guevara', pt: 'Che Guevara' }, dimensions: ['R'], photo: '/characters/che.jpg', description: { es: 'Rebelde que desafía el sistema cuando lo considera injusto.', en: 'Rebel who challenges the system when they consider it unjust.', fr: 'Rebelle qui défie le système lorsqu\'il le juge injuste.', de: 'Rebell, der das System herausfordert, wenn er es für ungerecht hält.', it: 'Ribelle che sfida il sistema quando lo considera ingiusto.', pt: 'Rebelde que desafia o sistema quando o considera injusto.' }, philosophy: { es: 'No aceptas el status quo cuando es injusto. Prefieres la acción directa sobre la diplomacia, y crees que el cambio real requiere valentía para enfrentar al sistema.', en: 'You do not accept the status quo when it is unjust. You prefer direct action over diplomacy, and believe real change requires courage to confront the system.', fr: 'Vous n\'acceptez pas le statu quo lorsqu\'il est injuste. Vous préférez l\'action directe à la diplomatie, et croyez que le vrai changement nécessite du courage pour affronter le système.', de: 'Du akzeptierst den Status quo nicht, wenn er ungerecht ist. Du bevorzugst direkte Aktion gegenüber Diplomatie und glaubst, dass echter Wandel Mut erfordert, das System zu konfrontieren.', it: 'Non accetti lo status quo quando è ingiusto. Preferisci l\'azione diretta alla diplomazia e credi che il vero cambiamento richieda coraggio per affrontare il sistema.', pt: 'Você não aceita o status quo quando é injusto. Prefere a ação direta à diplomacia e acredita que a mudança real requer coragem para enfrentar o sistema.' } },
        { name: { es: 'Nelson Mandela', en: 'Nelson Mandela', fr: 'Nelson Mandela', de: 'Nelson Mandela', it: 'Nelson Mandela', pt: 'Nelson Mandela' }, dimensions: ['P', 'I'], photo: '/characters/mandela.jpg', description: { es: 'Combina visión pragmática con principios inquebrantables.', en: 'Combines pragmatic vision with unbreakable principles.', fr: 'Combine vision pragmatique avec des principes inébranlables.', de: 'Kombiniert pragmatische Vision mit unerschütterlichen Prinzipien.', it: 'Combina visione pragmatica con principi incrollabili.', pt: 'Combina visão pragmática com princípios inquebráveis.' }, philosophy: { es: 'Sabes cuándo ser firme y cuándo ser flexible. Combinas la estrategia con la integridad, entendiendo que los grandes cambios requieren tanto paciencia como convicción.', en: 'You know when to be firm and when to be flexible. You combine strategy with integrity, understanding that great changes require both patience and conviction.', fr: 'Vous savez quand être ferme et quand être flexible. Vous combinez stratégie et intégrité, comprenant que les grands changements nécessitent à la fois de la patience et de la conviction.', de: 'Du weißt, wann du fest und wann du flexibel sein sollst. Du kombinierst Strategie mit Integrität und verstehst, dass große Veränderungen sowohl Geduld als auch Überzeugung erfordern.', it: 'Sai quando essere fermo e quando essere flessibile. Combini strategia con integrità, capendo che i grandi cambiamenti richiedono sia pazienza che convinzione.', pt: 'Você sabe quando ser firme e quando ser flexível. Combina estratégia com integridade, entendendo que grandes mudanças requerem tanto paciência quanto convicção.' } },
        { name: { es: 'Oprah Winfrey', en: 'Oprah Winfrey', fr: 'Oprah Winfrey', de: 'Oprah Winfrey', it: 'Oprah Winfrey', pt: 'Oprah Winfrey' }, dimensions: ['P', 'E'], photo: '/characters/oprah.jpg', description: { es: 'Pragmática pero siempre centrada en las personas.', en: 'Pragmatic but always focused on people.', fr: 'Pragmatique mais toujours centrée sur les personnes.', de: 'Pragmatisch, aber immer auf Menschen ausgerichtet.', it: 'Pragmatica ma sempre centrata sulle persone.', pt: 'Pragmática mas sempre centrada nas pessoas.' }, philosophy: { es: 'Eres efectivo/a y estratégico/a, pero nunca pierdes de vista a las personas. Crees que el éxito real viene de combinar inteligencia práctica con genuino interés por el bienestar de otros.', en: 'You are effective and strategic, but never lose sight of people. You believe real success comes from combining practical intelligence with genuine interest in the well-being of others.', fr: 'Vous êtes efficace et stratégique, mais ne perdez jamais les personnes de vue. Vous croyez que le vrai succès vient de combiner intelligence pratique avec un intérêt sincère pour le bien-être des autres.', de: 'Du bist effektiv und strategisch, verlierst aber nie die Menschen aus dem Blick. Du glaubst, dass echter Erfolg aus der Verbindung von praktischer Intelligenz mit echtem Interesse am Wohlergehen anderer kommt.', it: 'Sei efficace e strategico, ma non perdi mai di vista le persone. Credi che il vero successo venga dalla combinazione di intelligenza pratica con genuino interesse per il benessere degli altri.', pt: 'Você é eficaz e estratégico, mas nunca perde as pessoas de vista. Acredita que o sucesso real vem de combinar inteligência prática com interesse genuíno pelo bem-estar dos outros.' } },
        { name: { es: 'Martin Luther King Jr.', en: 'Martin Luther King Jr.', fr: 'Martin Luther King Jr.', de: 'Martin Luther King Jr.', it: 'Martin Luther King Jr.', pt: 'Martin Luther King Jr.' }, dimensions: ['I', 'R'], photo: '/characters/mlk.jpg', description: { es: 'Idealista que desafía lo establecido de forma pacífica.', en: 'Idealist who peacefully challenges the established order.', fr: 'Idéaliste qui défie l\'ordre établi de manière pacifique.', de: 'Idealist, der die etablierte Ordnung auf friedliche Weise herausfordert.', it: 'Idealista che sfida l\'ordine stabilito in modo pacifico.', pt: 'Idealista que desafia o estabelecido de forma pacífica.' }, philosophy: { es: 'Crees en un mundo mejor y estás dispuesto/a a luchar por él, pero desde los principios. Desafías la injusticia no con violencia, sino con la fuerza moral de tus convicciones.', en: 'You believe in a better world and are willing to fight for it, but from principles. You challenge injustice not with violence, but with the moral force of your convictions.', fr: 'Vous croyez en un monde meilleur et êtes prêt à vous battre pour lui, mais à partir de principes. Vous défiez l\'injustice non par la violence, mais par la force morale de vos convictions.', de: 'Du glaubst an eine bessere Welt und bist bereit, für sie zu kämpfen, aber aus Prinzipien heraus. Du bekämpfst Ungerechtigkeit nicht mit Gewalt, sondern mit der moralischen Kraft deiner Überzeugungen.', it: 'Credi in un mondo migliore e sei disposto a combatterci, ma partendo dai principi. Sfidi l\'ingiustizia non con la violenza, ma con la forza morale delle tue convinzioni.', pt: 'Você acredita em um mundo melhor e está disposto a lutar por ele, mas com princípios. Você desafia a injustiça não com violência, mas com a força moral de suas convicções.' } },
        { name: { es: 'Frida Kahlo', en: 'Frida Kahlo', fr: 'Frida Kahlo', de: 'Frida Kahlo', it: 'Frida Kahlo', pt: 'Frida Kahlo' }, dimensions: ['E', 'R'], photo: '/characters/frida.jpg', description: { es: 'Empática y auténtica, rompe moldes desde la vulnerabilidad.', en: 'Empathetic and authentic, breaks molds from vulnerability.', fr: 'Empathique et authentique, brise les moules depuis la vulnérabilité.', de: 'Einfühlsam und authentisch, bricht Formen aus der Verletzlichkeit heraus.', it: 'Empatica e autentica, rompe gli schemi dalla vulnerabilità.', pt: 'Empática e autêntica, quebra moldes desde a vulnerabilidade.' }, philosophy: { es: 'Tu sensibilidad es tu superpoder. Sientes profundamente y no temes mostrarlo, desafiando las normas desde la autenticidad. Crees que la vulnerabilidad es una forma de rebeldía.', en: 'Your sensitivity is your superpower. You feel deeply and are not afraid to show it, challenging norms from authenticity. You believe vulnerability is a form of rebellion.', fr: 'Votre sensibilité est votre superpouvoir. Vous ressentez profondément et n\'avez pas peur de le montrer, défiant les normes depuis l\'authenticité. Vous croyez que la vulnérabilité est une forme de rébellion.', de: 'Deine Sensibilität ist deine Superkraft. Du fühlst tief und hast keine Angst, es zu zeigen, und forderst Normen aus Authentizität heraus. Du glaubst, dass Verletzlichkeit eine Form der Rebellion ist.', it: 'La tua sensibilità è il tuo superpotere. Senti profondamente e non hai paura di mostrarlo, sfidando le norme dall\'autenticità. Credi che la vulnerabilità sia una forma di ribellione.', pt: 'Sua sensibilidade é seu superpoder. Você sente profundamente e não tem medo de mostrar, desafiando as normas desde a autenticidade. Você acredita que a vulnerabilidade é uma forma de rebeldia.' } },
      ],
    },
    create: {
      slug: 'ethics',
      title: { es: 'Dilemas Éticos', en: 'Ethical Dilemmas', fr: 'Dilemmes Éthiques', de: 'Ethische Dilemmata', it: 'Dilemmi Etici', pt: 'Dilemas Éticos' },
      description: { es: '10 situaciones éticas complejas que revelarán cómo piensas. Al final, descubre qué personaje histórico comparte tu filosofía de vida.', en: '10 complex ethical situations that will reveal how you think. At the end, discover which historical figure shares your philosophy of life.', fr: '10 situations éthiques complexes qui révéleront comment vous pensez. À la fin, découvrez quel personnage historique partage votre philosophie de vie.', de: '10 komplexe ethische Situationen, die zeigen, wie du denkst. Am Ende erfährst du, welche historische Persönlichkeit deine Lebensphilosophie teilt.', it: '10 situazioni etiche complesse che riveleranno come pensi. Alla fine, scopri quale personaggio storico condivide la tua filosofia di vita.', pt: '10 situações éticas complexas que revelarão como você pensa. No final, descubra qual personagem histórico compartilha sua filosofia de vida.' },
      scenarioLabel: { es: 'Dilema', en: 'Dilemma', fr: 'Dilemme', de: 'Dilemma', it: 'Dilemma', pt: 'Dilema' },
      categoryId: catMap['moral'],
      sortOrder: 1,
      dimensionLabels: {
        es: { P: 'Pragmatismo', I: 'Idealismo', E: 'Empatía', R: 'Rebeldía' },
        en: { P: 'Pragmatism', I: 'Idealism', E: 'Empathy', R: 'Rebellion' },
        fr: { P: 'Pragmatisme', I: 'Idéalisme', E: 'Empathie', R: 'Rébellion' },
        de: { P: 'Pragmatismus', I: 'Idealismus', E: 'Empathie', R: 'Rebellion' },
        it: { P: 'Pragmatismo', I: 'Idealismo', E: 'Empatia', R: 'Ribellione' },
        pt: { P: 'Pragmatismo', I: 'Idealismo', E: 'Empatia', R: 'Rebeldia' },
      },
      questions: [
        { id: 1, situation: { es: 'Un tren descontrolado se dirige hacia cinco personas atadas a las vías. Puedes desviar el tren a otra vía donde solo hay una persona. ¿Qué haces?', en: 'A runaway trolley is heading towards five people tied to the tracks. You can divert it to another track where there is only one person. What do you do?', fr: 'Un tramway incontrôlable se dirige vers cinq personnes attachées aux rails. Vous pouvez le dévier sur une autre voie où il n\'y a qu\'une seule personne. Que faites-vous?', de: 'Eine außer Kontrolle geratene Straßenbahn fährt auf fünf an die Gleise gefesselte Menschen zu. Du kannst sie auf ein anderes Gleis umleiten, wo nur eine Person ist. Was tust du?', it: 'Un tram fuori controllo si dirige verso cinque persone legate ai binari. Puoi deviarlo su un altro binario dove c\'è solo una persona. Cosa fai?', pt: 'Um bonde descontrolado se dirige a cinco pessoas amarradas nos trilhos. Você pode desviá-lo para outro trilho onde há apenas uma pessoa. O que você faz?' }, options: [
          { text: { es: 'Desvío el tren. Salvar cinco vidas a costa de una es la decisión más lógica.', en: 'I divert the trolley. Saving five lives at the cost of one is the most logical decision.', fr: 'Je dévie le tramway. Sauver cinq vies au prix d\'une est la décision la plus logique.', de: 'Ich leite die Straßenbahn um. Fünf Leben auf Kosten eines zu retten ist die logischste Entscheidung.', it: 'Desvio il tram. Salvare cinque vite a costo di una è la decisione più logica.', pt: 'Desvio o bonde. Salvar cinco vidas ao custo de uma é a decisão mais lógica.' }, dimension: 'P' },
          { text: { es: 'No intervengo. No tengo derecho a decidir quién vive y quién muere.', en: 'I don\'t intervene. I have no right to decide who lives and who dies.', fr: 'Je n\'interviens pas. Je n\'ai pas le droit de décider qui vit et qui meurt.', de: 'Ich greife nicht ein. Ich habe kein Recht zu entscheiden, wer lebt und wer stirbt.', it: 'Non intervengo. Non ho il diritto di decidere chi vive e chi muore.', pt: 'Não intervenho. Não tenho o direito de decidir quem vive e quem morre.' }, dimension: 'I' },
          { text: { es: 'Intento advertir a todos gritando, aunque sea poco probable que funcione.', en: 'I try to warn everyone by shouting, even if it\'s unlikely to work.', fr: 'J\'essaie de prévenir tout le monde en criant, même si c\'est peu probable.', de: 'Ich versuche alle durch Rufen zu warnen, auch wenn es unwahrscheinlich ist, dass es funktioniert.', it: 'Cerco di avvisare tutti urlando, anche se è improbabile che funzioni.', pt: 'Tento alertar todos gritando, mesmo que seja improvável que funcione.' }, dimension: 'E' },
          { text: { es: 'Busco una tercera opción: sabotear el tren, bloquear las vías, lo que sea.', en: 'I look for a third option: sabotage the trolley, block the tracks, whatever it takes.', fr: 'Je cherche une troisième option: saboter le tramway, bloquer les voies, quoi que ce soit.', de: 'Ich suche nach einer dritten Option: die Straßenbahn sabotieren, die Gleise blockieren, was auch immer.', it: 'Cerco una terza opzione: sabotare il tram, bloccare i binari, qualsiasi cosa.', pt: 'Busco uma terceira opção: sabotar o bonde, bloquear os trilhos, o que for.' }, dimension: 'R' },
        ] },
        { id: 2, situation: { es: 'Descubres que tu mejor amigo, funcionario público, está desviando fondos. Nadie más lo sabe.', en: 'You discover that your best friend, a public official, is embezzling funds. Nobody else knows.', fr: 'Vous découvrez que votre meilleur ami, fonctionnaire public, détourne des fonds. Personne d\'autre ne le sait.', de: 'Du entdeckst, dass dein bester Freund, ein Beamter, Gelder veruntreut. Niemand sonst weiß es.', it: 'Scopri che il tuo migliore amico, un funzionario pubblico, sta sottraendo fondi. Nessun altro lo sa.', pt: 'Você descobre que seu melhor amigo, funcionário público, está desviando fundos. Ninguém mais sabe.' }, options: [
          { text: { es: 'Lo denuncio anónimamente. El daño público es mayor que nuestra amistad.', en: 'I report it anonymously. The public harm outweighs our friendship.', fr: 'Je le dénonce anonymement. Le préjudice public est plus important que notre amitié.', de: 'Ich zeige es anonym an. Der öffentliche Schaden überwiegt unsere Freundschaft.', it: 'Lo denuncio anonimamente. Il danno pubblico supera la nostra amicizia.', pt: 'Denuncio anonimamente. O dano público é maior que nossa amizade.' }, dimension: 'P' },
          { text: { es: 'Lo denuncio abiertamente. La corrupción debe enfrentarse sin importar quién sea.', en: 'I report it openly. Corruption must be confronted regardless of who it is.', fr: 'Je le dénonce ouvertement. La corruption doit être confrontée peu importe qui c\'est.', de: 'Ich zeige es offen an. Korruption muss bekämpft werden, egal wer es ist.', it: 'Lo denuncio apertamente. La corruzione deve essere affrontata indipendentemente da chi sia.', pt: 'Denuncio abertamente. A corrupção deve ser enfrentada independente de quem seja.' }, dimension: 'I' },
          { text: { es: 'Hablo primero con él en privado para entender su situación.', en: 'I talk to him privately first to understand his situation.', fr: 'Je lui parle d\'abord en privé pour comprendre sa situation.', de: 'Ich spreche zuerst privat mit ihm, um seine Situation zu verstehen.', it: 'Gli parlo prima in privato per capire la sua situazione.', pt: 'Falo com ele em particular primeiro para entender sua situação.' }, dimension: 'E' },
          { text: { es: 'Filtro la información a la prensa para que el sistema rinda cuentas.', en: 'I leak the information to the press so the system is held accountable.', fr: 'Je fuite les informations à la presse pour que le système rende des comptes.', de: 'Ich leake die Informationen an die Presse, damit das System zur Rechenschaft gezogen wird.', it: 'Faccio trapelare le informazioni alla stampa affinché il sistema sia ritenuto responsabile.', pt: 'Vaso as informações para a imprensa para que o sistema preste contas.' }, dimension: 'R' },
        ] },
        { id: 3, situation: { es: 'Tu pareja necesita un medicamento carísimo y no pueden pagarlo. La farmacia se niega a hacer excepciones.', en: 'Your partner needs an extremely expensive medication and you cannot afford it. The pharmacy refuses to make exceptions.', fr: 'Votre partenaire a besoin d\'un médicament très coûteux et vous ne pouvez pas vous le permettre. La pharmacie refuse de faire des exceptions.', de: 'Dein Partner braucht ein sehr teures Medikament und ihr könnt es nicht bezahlen. Die Apotheke weigert sich, Ausnahmen zu machen.', it: 'Il tuo partner ha bisogno di un farmaco costosissimo e non potete permettervelo. La farmacia si rifiuta di fare eccezioni.', pt: 'Seu parceiro precisa de um medicamento caríssimo e não podem pagar. A farmácia se recusa a fazer exceções.' }, options: [
          { text: { es: 'Busco genéricos, crowdfunding, programas de ayuda. Hay que ser estratégico.', en: 'I look for generics, crowdfunding, assistance programs. You have to be strategic.', fr: 'Je cherche des génériques, du financement participatif, des programmes d\'aide. Il faut être stratégique.', de: 'Ich suche nach Generika, Crowdfunding, Hilfsprogrammen. Man muss strategisch sein.', it: 'Cerco farmaci generici, crowdfunding, programmi di assistenza. Bisogna essere strategici.', pt: 'Busco genéricos, crowdfunding, programas de ajuda. É preciso ser estratégico.' }, dimension: 'P' },
          { text: { es: 'Busco todas las vías legales posibles aunque tome más tiempo.', en: 'I seek every possible legal avenue even if it takes more time.', fr: 'Je cherche toutes les voies légales possibles même si cela prend plus de temps.', de: 'Ich suche alle möglichen legalen Wege, auch wenn es mehr Zeit in Anspruch nimmt.', it: 'Cerco tutte le vie legali possibili anche se richiede più tempo.', pt: 'Busco todas as vias legais possíveis mesmo que demore mais.' }, dimension: 'I' },
          { text: { es: 'Robo el medicamento sin dudarlo. La vida de mi pareja vale más que cualquier ley.', en: 'I steal the medication without hesitation. My partner\'s life is worth more than any law.', fr: 'Je vole le médicament sans hésiter. La vie de mon partenaire vaut plus que n\'importe quelle loi.', de: 'Ich stehle das Medikament ohne zu zögern. Das Leben meines Partners ist mehr wert als jedes Gesetz.', it: 'Rubo il farmaco senza esitare. La vita del mio partner vale più di qualsiasi legge.', pt: 'Roubo o medicamento sem hesitar. A vida do meu parceiro vale mais que qualquer lei.' }, dimension: 'E' },
          { text: { es: 'Organizo una protesta pública contra el precio abusivo del medicamento.', en: 'I organize a public protest against the abusive price of the medication.', fr: 'J\'organise une protestation publique contre le prix abusif du médicament.', de: 'Ich organisiere einen öffentlichen Protest gegen den überhöhten Preis des Medikaments.', it: 'Organizzo una protesta pubblica contro il prezzo abusivo del farmaco.', pt: 'Organizo um protesto público contra o preço abusivo do medicamento.' }, dimension: 'R' },
        ] },
        { id: 4, situation: { es: 'Durante la guerra, escondes a una familia perseguida. Soldados tocan tu puerta y preguntan si hay alguien escondido.', en: 'During the war, you are hiding a persecuted family. Soldiers knock on your door and ask if anyone is hidden inside.', fr: 'Pendant la guerre, vous cachez une famille persécutée. Des soldats frappent à votre porte et demandent si quelqu\'un est caché.', de: 'Während des Krieges versteckst du eine verfolgte Familie. Soldaten klopfen an deine Tür und fragen, ob jemand versteckt ist.', it: 'Durante la guerra, nascondi una famiglia perseguitata. I soldati bussano alla tua porta e chiedono se c\'è qualcuno nascosto.', pt: 'Durante a guerra, você esconde uma família perseguida. Soldados batem à sua porta e perguntam se há alguém escondido.' }, options: [
          { text: { es: 'Miento sin dudarlo. Es la única forma realista de protegerlos.', en: 'I lie without hesitation. It\'s the only realistic way to protect them.', fr: 'Je mens sans hésiter. C\'est le seul moyen réaliste de les protéger.', de: 'Ich lüge ohne zu zögern. Es ist der einzig realistische Weg, sie zu schützen.', it: 'Mento senza esitare. È l\'unico modo realistico per proteggerli.', pt: 'Minto sem hesitar. É a única forma realista de protegê-los.' }, dimension: 'P' },
          { text: { es: 'Me niego a responder. No puedo mentir, pero tampoco los delato.', en: 'I refuse to answer. I cannot lie, but I won\'t betray them either.', fr: 'Je refuse de répondre. Je ne peux pas mentir, mais je ne les trahirai pas non plus.', de: 'Ich weigere mich zu antworten. Ich kann nicht lügen, aber ich verrate sie auch nicht.', it: 'Mi rifiuto di rispondere. Non posso mentire, ma non li tradirò nemmeno.', pt: 'Recuso-me a responder. Não posso mentir, mas também não os denuncio.' }, dimension: 'I' },
          { text: { es: 'Miento y además los invito a pasar café para alejar sospechas.', en: 'I lie and also invite them in for coffee to dispel suspicion.', fr: 'Je mens et je les invite aussi à prendre un café pour dissiper les soupçons.', de: 'Ich lüge und lade sie auch zum Kaffee ein, um Verdacht zu zerstreuen.', it: 'Mento e li invito anche a prendere un caffè per allontanare i sospetti.', pt: 'Minto e também os convido para um café para afastar suspeitas.' }, dimension: 'E' },
          { text: { es: 'Los enfrento: "Aunque los tuviera, no se los entregaría."', en: 'I confront them: "Even if I had them, I would not hand them over."', fr: 'Je les affronte: "Même si je les avais, je ne vous les livrerais pas."', de: 'Ich konfrontiere sie: "Selbst wenn ich sie hätte, würde ich sie nicht ausliefern."', it: 'Li affronto: "Anche se li avessi, non ve li consegnerei."', pt: 'Os enfrento: "Mesmo que os tivesse, não os entregaria."' }, dimension: 'R' },
        ] },
        { id: 5, situation: { es: 'Te ofrecen un trabajo increíblemente bien pagado en una empresa que contamina ríos en comunidades pobres.', en: 'You are offered an incredibly well-paid job at a company that pollutes rivers in poor communities.', fr: 'On vous offre un travail incroyablement bien payé dans une entreprise qui pollue les rivières dans les communautés pauvres.', de: 'Dir wird eine unglaublich gut bezahlte Stelle in einem Unternehmen angeboten, das Flüsse in armen Gemeinden verschmutzt.', it: 'Ti viene offerto un lavoro incredibilmente ben pagato in un\'azienda che inquina i fiumi nelle comunità povere.', pt: 'Você recebe uma oferta de emprego incrivelmente bem pago em uma empresa que polui rios em comunidades pobres.' }, options: [
          { text: { es: 'Acepto y uso mi posición interna para impulsar cambios graduales.', en: 'I accept and use my position from inside to push for gradual changes.', fr: 'J\'accepte et j\'utilise ma position interne pour impulser des changements progressifs.', de: 'Ich nehme an und nutze meine interne Position, um schrittweise Veränderungen voranzutreiben.', it: 'Accetto e uso la mia posizione interna per promuovere cambiamenti graduali.', pt: 'Aceito e uso minha posição interna para impulsionar mudanças graduais.' }, dimension: 'P' },
          { text: { es: 'Lo rechazo. No puedo ser cómplice de algo que viola mis principios.', en: 'I reject it. I cannot be complicit in something that violates my principles.', fr: 'Je le refuse. Je ne peux pas être complice de quelque chose qui viole mes principes.', de: 'Ich lehne es ab. Ich kann nicht Komplize von etwas sein, das meine Prinzipien verletzt.', it: 'Lo rifiuto. Non posso essere complice di qualcosa che viola i miei principi.', pt: 'Recuso. Não posso ser cúmplice de algo que viola meus princípios.' }, dimension: 'I' },
          { text: { es: 'Lo rechazo y busco formas de ayudar a las comunidades afectadas.', en: 'I reject it and look for ways to help the affected communities.', fr: 'Je le refuse et cherche des moyens d\'aider les communautés touchées.', de: 'Ich lehne es ab und suche nach Wegen, den betroffenen Gemeinschaften zu helfen.', it: 'Lo rifiuto e cerco modi per aiutare le comunità colpite.', pt: 'Recuso e busco formas de ajudar as comunidades afetadas.' }, dimension: 'E' },
          { text: { es: 'Acepto, recopilo evidencia desde dentro y luego la hago pública.', en: 'I accept, collect evidence from inside, and then make it public.', fr: 'J\'accepte, je recueille des preuves de l\'intérieur, puis je les rends publiques.', de: 'Ich nehme an, sammle Beweise von innen und mache sie dann öffentlich.', it: 'Accetto, raccolgo prove dall\'interno e poi le rendo pubbliche.', pt: 'Aceito, coletando evidências por dentro e depois as tornando públicas.' }, dimension: 'R' },
        ] },
        { id: 6, situation: { es: 'Descubres que tu padre tiene una segunda familia secreta. Tu madre no sabe nada.', en: 'You discover that your father has a secret second family. Your mother knows nothing.', fr: 'Vous découvrez que votre père a une deuxième famille secrète. Votre mère ne sait rien.', de: 'Du entdeckst, dass dein Vater eine zweite Geheimfamilie hat. Deine Mutter weiß nichts.', it: 'Scopri che tuo padre ha una seconda famiglia segreta. Tua madre non sa nulla.', pt: 'Você descobre que seu pai tem uma segunda família secreta. Sua mãe não sabe de nada.' }, options: [
          { text: { es: 'Confronto a mi padre en privado y le doy un plazo para resolver la situación.', en: 'I confront my father privately and give him a deadline to resolve the situation.', fr: 'Je confronte mon père en privé et lui donne un délai pour résoudre la situation.', de: 'Ich konfrontiere meinen Vater privat und gebe ihm eine Frist, die Situation zu lösen.', it: 'Confronto mio padre in privato e gli do un termine per risolvere la situazione.', pt: 'Confronto meu pai em particular e lhe dou um prazo para resolver a situação.' }, dimension: 'P' },
          { text: { es: 'Le digo la verdad a mi madre. Tiene derecho a saber, pase lo que pase.', en: 'I tell my mother the truth. She has the right to know, no matter what.', fr: 'Je dis la vérité à ma mère. Elle a le droit de savoir, quoi qu\'il arrive.', de: 'Ich sage meiner Mutter die Wahrheit. Sie hat das Recht zu wissen, was auch immer passiert.', it: 'Dico la verità a mia madre. Ha il diritto di sapere, accada quel che accada.', pt: 'Digo a verdade para minha mãe. Ela tem o direito de saber, aconteça o que acontecer.' }, dimension: 'I' },
          { text: { es: 'Busco apoyo profesional primero para entender cómo minimizar el daño.', en: 'I seek professional support first to understand how to minimize the damage.', fr: 'Je cherche d\'abord un soutien professionnel pour comprendre comment minimiser les dommages.', de: 'Ich suche zuerst professionelle Unterstützung, um zu verstehen, wie ich den Schaden minimieren kann.', it: 'Cerco prima supporto professionale per capire come minimizzare il danno.', pt: 'Busco apoio profissional primeiro para entender como minimizar o dano.' }, dimension: 'E' },
          { text: { es: 'Enfrento a mi padre públicamente en una reunión familiar.', en: 'I confront my father publicly at a family gathering.', fr: 'Je confronte mon père publiquement lors d\'une réunion de famille.', de: 'Ich konfrontiere meinen Vater öffentlich bei einem Familientreffen.', it: 'Confronto mio padre pubblicamente durante un incontro di famiglia.', pt: 'Confronto meu pai publicamente em uma reunião familiar.' }, dimension: 'R' },
        ] },
        { id: 7, situation: { es: 'Una ley prohíbe dar comida a personas sin hogar en espacios públicos.', en: 'A law prohibits giving food to homeless people in public spaces.', fr: 'Une loi interdit de donner de la nourriture aux sans-abri dans les espaces publics.', de: 'Ein Gesetz verbietet es, Obdachlosen in öffentlichen Räumen Essen zu geben.', it: 'Una legge vieta di dare cibo ai senzatetto negli spazi pubblici.', pt: 'Uma lei proíbe dar comida a pessoas sem-teto em espaços públicos.' }, options: [
          { text: { es: 'Busco vacíos legales: reparto en propiedad privada o creo un comedor social.', en: 'I look for legal loopholes: distribute on private property or create a soup kitchen.', fr: 'Je cherche des failles juridiques: distribuer sur propriété privée ou créer une cantine sociale.', de: 'Ich suche nach rechtlichen Lücken: Auf Privatgelände verteilen oder eine Suppenküche gründen.', it: 'Cerco scappatoie legali: distribuire su proprietà privata o creare una mensa sociale.', pt: 'Busco brechas legais: distribuir em propriedade privada ou criar um refeitório social.' }, dimension: 'P' },
          { text: { es: 'Desobedezco la ley abiertamente. Una ley injusta no merece obediencia.', en: 'I openly disobey the law. An unjust law does not deserve obedience.', fr: 'Je désobéis ouvertement à la loi. Une loi injuste ne mérite pas l\'obéissance.', de: 'Ich verweigere offen den Gehorsam. Ein ungerechtes Gesetz verdient keinen Gehorsam.', it: 'Disobbedisco apertamente alla legge. Una legge ingiusta non merita obbedienza.', pt: 'Desobedeço a lei abertamente. Uma lei injusta não merece obediência.' }, dimension: 'I' },
          { text: { es: 'Sigo ayudando discretamente y conecto a estas personas con servicios sociales.', en: 'I continue helping discreetly and connect these people with social services.', fr: 'Je continue d\'aider discrètement et je mets ces personnes en contact avec les services sociaux.', de: 'Ich helfe weiterhin diskret und verbinde diese Menschen mit Sozialdiensten.', it: 'Continuo ad aiutare discretamente e connetto queste persone con i servizi sociali.', pt: 'Continuo ajudando discretamente e conecto essas pessoas com serviços sociais.' }, dimension: 'E' },
          { text: { es: 'Organizo desobediencia civil masiva para presionar y cambiar la ley.', en: 'I organize mass civil disobedience to pressure for and change the law.', fr: 'J\'organise une désobéissance civile massive pour faire pression et changer la loi.', de: 'Ich organisiere massiven zivilen Ungehorsam, um das Gesetz zu ändern.', it: 'Organizzo disobbedienza civile di massa per fare pressione e cambiare la legge.', pt: 'Organizo desobediência civil em massa para pressionar e mudar a lei.' }, dimension: 'R' },
        ] },
        { id: 8, situation: { es: 'Alguien que te hizo mucho daño en el pasado ahora está en una crisis terrible y te pide ayuda.', en: 'Someone who hurt you deeply in the past is now in a terrible crisis and asks for your help.', fr: 'Quelqu\'un qui vous a beaucoup blessé dans le passé est maintenant dans une crise terrible et vous demande de l\'aide.', de: 'Jemand, der dir in der Vergangenheit sehr geschadet hat, befindet sich jetzt in einer schrecklichen Krise und bittet dich um Hilfe.', it: 'Qualcuno che ti ha fatto molto del male in passato è ora in una crisi terribile e ti chiede aiuto.', pt: 'Alguém que te machucou muito no passado agora está em uma crise terrível e pede sua ajuda.' }, options: [
          { text: { es: 'Lo ayudo, pero establezco límites claros. No olvido, pero soy práctico.', en: 'I help them, but establish clear boundaries. I don\'t forget, but I\'m practical.', fr: 'Je l\'aide, mais j\'établis des limites claires. Je n\'oublie pas, mais je suis pragmatique.', de: 'Ich helfe ihm, setze aber klare Grenzen. Ich vergesse nicht, aber ich bin praktisch.', it: 'Lo aiuto, ma stabilisco limiti chiari. Non dimentico, ma sono pratico.', pt: 'Ajudo, mas estabeleço limites claros. Não esqueço, mas sou prático.' }, dimension: 'P' },
          { text: { es: 'Lo ayudo porque es lo correcto, independientemente de lo que me haya hecho.', en: 'I help them because it\'s the right thing to do, regardless of what they did to me.', fr: 'Je l\'aide parce que c\'est la bonne chose à faire, indépendamment de ce qu\'il m\'a fait.', de: 'Ich helfe ihm, weil es das Richtige ist, unabhängig davon, was er mir angetan hat.', it: 'Lo aiuto perché è la cosa giusta da fare, indipendentemente da quello che mi ha fatto.', pt: 'Ajudo porque é a coisa certa a fazer, independentemente do que me fez.' }, dimension: 'I' },
          { text: { es: 'Lo ayudo de corazón. El sufrimiento de cualquier persona me conmueve.', en: 'I help them wholeheartedly. The suffering of any person moves me.', fr: 'Je l\'aide de tout cœur. La souffrance de toute personne me touche.', de: 'Ich helfe ihm von Herzen. Das Leiden jeder Person berührt mich.', it: 'Lo aiuto di cuore. La sofferenza di qualsiasi persona mi commuove.', pt: 'Ajudo de coração. O sofrimento de qualquer pessoa me comove.' }, dimension: 'E' },
          { text: { es: 'No lo ayudo. Las acciones tienen consecuencias y debe enfrentarlas.', en: 'I don\'t help them. Actions have consequences and they must face them.', fr: 'Je ne l\'aide pas. Les actions ont des conséquences et il doit y faire face.', de: 'Ich helfe ihm nicht. Handlungen haben Konsequenzen und er muss sich ihnen stellen.', it: 'Non lo aiuto. Le azioni hanno conseguenze e deve affrontarle.', pt: 'Não ajudo. As ações têm consequências e ela deve enfrentá-las.' }, dimension: 'R' },
        ] },
        { id: 9, situation: { es: 'Eres científico y descubres que tu empresa farmacéutica ocultó efectos secundarios graves de un medicamento popular.', en: 'You are a scientist and discover that your pharmaceutical company has hidden serious side effects of a popular medication.', fr: 'Vous êtes scientifique et découvrez que votre entreprise pharmaceutique a caché de graves effets secondaires d\'un médicament populaire.', de: 'Du bist Wissenschaftler und entdeckst, dass dein Pharmaunternehmen schwerwiegende Nebenwirkungen eines beliebten Medikaments verborgen hat.', it: 'Sei uno scienziato e scopri che la tua azienda farmaceutica ha nascosto gravi effetti collaterali di un farmaco popolare.', pt: 'Você é cientista e descobre que sua empresa farmacêutica ocultou efeitos colaterais graves de um medicamento popular.' }, options: [
          { text: { es: 'Documento todo meticulosamente y busco un abogado antes de hacer cualquier movimiento.', en: 'I document everything meticulously and get a lawyer before making any move.', fr: 'Je documente tout méticuleusement et cherche un avocat avant de faire quoi que ce soit.', de: 'Ich dokumentiere alles akribisch und konsultiere einen Anwalt, bevor ich irgendeinen Schritt unternehme.', it: 'Documento tutto meticolosamente e cerco un avvocato prima di fare qualsiasi mossa.', pt: 'Documento tudo meticulosamente e busco um advogado antes de fazer qualquer movimento.' }, dimension: 'P' },
          { text: { es: 'Denuncio inmediatamente ante las autoridades. La salud pública no puede esperar.', en: 'I report immediately to the authorities. Public health cannot wait.', fr: 'Je dénonce immédiatement aux autorités. La santé publique ne peut pas attendre.', de: 'Ich erstattet sofort Anzeige bei den Behörden. Die öffentliche Gesundheit kann nicht warten.', it: 'Denuncio immediatamente alle autorità. La salute pubblica non può aspettare.', pt: 'Denuncio imediatamente às autoridades. A saúde pública não pode esperar.' }, dimension: 'I' },
          { text: { es: 'Pienso en los pacientes afectados y sus familias. Denuncio y busco apoyarlos.', en: 'I think about the affected patients and their families. I report and seek to support them.', fr: 'Je pense aux patients touchés et à leurs familles. Je dénonce et cherche à les soutenir.', de: 'Ich denke an die betroffenen Patienten und ihre Familien. Ich erstattet Anzeige und versuche, sie zu unterstützen.', it: 'Penso ai pazienti colpiti e alle loro famiglie. Denuncio e cerco di supportarli.', pt: 'Penso nos pacientes afetados e suas famílias. Denuncio e busco apoiá-los.' }, dimension: 'E' },
          { text: { es: 'Filtro toda la información a medios independientes para que no puedan silenciarlo.', en: 'I leak all the information to independent media so they cannot silence it.', fr: 'Je fuite toutes les informations aux médias indépendants pour qu\'ils ne puissent pas les faire taire.', de: 'Ich leake alle Informationen an unabhängige Medien, damit sie es nicht zum Schweigen bringen können.', it: 'Faccio trapelare tutte le informazioni ai media indipendenti affinché non possano silenziarlo.', pt: 'Vaso todas as informações para a mídia independente para que não possam silenciá-las.' }, dimension: 'R' },
        ] },
        { id: 10, situation: { es: 'Un hospital propone usar IA para decidir qué pacientes reciben tratamiento prioritario cuando los recursos son limitados.', en: 'A hospital proposes using AI to decide which patients receive priority treatment when resources are limited.', fr: 'Un hôpital propose d\'utiliser l\'IA pour décider quels patients reçoivent un traitement prioritaire lorsque les ressources sont limitées.', de: 'Ein Krankenhaus schlägt vor, KI einzusetzen, um zu entscheiden, welche Patienten eine vorrangige Behandlung erhalten, wenn die Ressourcen begrenzt sind.', it: 'Un ospedale propone di usare l\'IA per decidere quali pazienti ricevono un trattamento prioritario quando le risorse sono limitate.', pt: 'Um hospital propõe usar IA para decidir quais pacientes recebem tratamento prioritário quando os recursos são limitados.' }, options: [
          { text: { es: 'A favor, si los datos son buenos. La IA puede ser más objetiva que los humanos.', en: 'In favor, if the data is good. AI can be more objective than humans.', fr: 'Pour, si les données sont bonnes. L\'IA peut être plus objective que les humains.', de: 'Dafür, wenn die Daten gut sind. KI kann objektiver sein als Menschen.', it: 'A favore, se i dati sono buoni. L\'IA può essere più obiettiva degli umani.', pt: 'A favor, se os dados forem bons. A IA pode ser mais objetiva que os humanos.' }, dimension: 'P' },
          { text: { es: 'En contra. Decisiones de vida o muerte deben ser tomadas por personas con criterio moral.', en: 'Against. Life or death decisions must be made by people with moral judgment.', fr: 'Contre. Les décisions de vie ou de mort doivent être prises par des personnes avec un jugement moral.', de: 'Dagegen. Entscheidungen über Leben und Tod müssen von Menschen mit moralischem Urteilsvermögen getroffen werden.', it: 'Contro. Le decisioni di vita o di morte devono essere prese da persone con giudizio morale.', pt: 'Contra. Decisões de vida ou morte devem ser tomadas por pessoas com critério moral.' }, dimension: 'I' },
          { text: { es: 'Solo si garantiza considerar factores humanos y no solo estadísticas frías.', en: 'Only if it guarantees considering human factors and not just cold statistics.', fr: 'Uniquement si elle garantit de prendre en compte les facteurs humains et pas seulement les statistiques froides.', de: 'Nur wenn es garantiert, menschliche Faktoren zu berücksichtigen und nicht nur kalte Statistiken.', it: 'Solo se garantisce di considerare fattori umani e non solo statistiche fredde.', pt: 'Apenas se garantir considerar fatores humanos e não apenas estatísticas frias.' }, dimension: 'E' },
          { text: { es: 'En contra. Es peligroso ceder el poder de decisión sobre vidas a sistemas que no podemos cuestionar.', en: 'Against. It is dangerous to cede decision-making power over lives to systems we cannot question.', fr: 'Contre. Il est dangereux de céder le pouvoir de décision sur des vies à des systèmes que nous ne pouvons pas questionner.', de: 'Dagegen. Es ist gefährlich, Entscheidungsgewalt über Leben an Systeme abzugeben, die wir nicht in Frage stellen können.', it: 'Contro. È pericoloso cedere il potere decisionale sulle vite a sistemi che non possiamo mettere in discussione.', pt: 'Contra. É perigoso ceder o poder de decisão sobre vidas a sistemas que não podemos questionar.' }, dimension: 'R' },
        ] },
      ],
      characters: [
        { name: { es: 'Winston Churchill', en: 'Winston Churchill', fr: 'Winston Churchill', de: 'Winston Churchill', it: 'Winston Churchill', pt: 'Winston Churchill' }, dimensions: ['P'], photo: '/characters/churchill.jpg', description: { es: 'Pragmático implacable que toma decisiones difíciles por el bien mayor.', en: 'Relentless pragmatist who makes difficult decisions for the greater good.', fr: 'Pragmatique implacable qui prend des décisions difficiles pour le bien commun.', de: 'Unnachgiebiger Pragmatiker, der schwierige Entscheidungen für das Gemeinwohl trifft.', it: 'Pragmatico implacabile che prende decisioni difficili per il bene maggiore.', pt: 'Pragmático implacável que toma decisões difíceis pelo bem maior.' }, philosophy: { es: 'Ves el mundo como es, no como quisieras que fuera. Tomas decisiones difíciles cuando otros dudan, priorizando resultados sobre sentimientos. Tu fortaleza está en la claridad estratégica.', en: 'You see the world as it is, not as you wish it were. You make difficult decisions when others hesitate, prioritizing results over feelings. Your strength lies in strategic clarity.', fr: 'Vous voyez le monde tel qu\'il est, pas tel que vous souhaiteriez qu\'il soit. Vous prenez des décisions difficiles quand d\'autres hésitent, en priorisant les résultats sur les sentiments.', de: 'Du siehst die Welt wie sie ist, nicht wie du sie dir wünschst. Du triffst schwierige Entscheidungen, wenn andere zögern, und priorisierst Ergebnisse über Gefühle.', it: 'Vedi il mondo com\'è, non come vorresti che fosse. Prendi decisioni difficili quando gli altri esitano, dando priorità ai risultati rispetto ai sentimenti.', pt: 'Você vê o mundo como ele é, não como gostaria que fosse. Toma decisões difíceis quando outros hesitam, priorizando resultados sobre sentimentos.' } },
        { name: { es: 'Mahatma Gandhi', en: 'Mahatma Gandhi', fr: 'Mahatma Gandhi', de: 'Mahatma Gandhi', it: 'Mahatma Gandhi', pt: 'Mahatma Gandhi' }, dimensions: ['I'], photo: '/characters/gandhi.jpg', description: { es: 'Idealista que no transige en principios sin importar las consecuencias.', en: 'Idealist who does not compromise on principles regardless of consequences.', fr: 'Idéaliste qui ne transige pas sur les principes quelles que soient les conséquences.', de: 'Idealist, der keine Kompromisse bei Prinzipien eingeht, egal was die Konsequenzen sind.', it: 'Idealista che non scende a compromessi sui principi indipendentemente dalle conseguenze.', pt: 'Idealista que não cede em princípios independentemente das consequências.' }, philosophy: { es: 'Tus principios no son negociables. Crees que el fin nunca justifica los medios y que la coherencia moral es la mayor fortaleza. Inspiras a otros con tu integridad inquebrantable.', en: 'Your principles are non-negotiable. You believe the end never justifies the means and that moral consistency is the greatest strength. You inspire others with your unbreakable integrity.', fr: 'Vos principes ne sont pas négociables. Vous croyez que la fin ne justifie jamais les moyens et que la cohérence morale est la plus grande force.', de: 'Deine Prinzipien sind nicht verhandelbar. Du glaubst, dass der Zweck nie die Mittel heiligt und moralische Konsequenz die größte Stärke ist.', it: 'I tuoi principi non sono negoziabili. Credi che il fine non giustifichi mai i mezzi e che la coerenza morale sia la forza più grande.', pt: 'Seus princípios não são negociáveis. Você acredita que o fim nunca justifica os meios e que a coerência moral é a maior fortaleza.' } },
        { name: { es: 'Princesa Diana', en: 'Princess Diana', fr: 'Princesse Diana', de: 'Prinzessin Diana', it: 'Principessa Diana', pt: 'Princesa Diana' }, dimensions: ['E'], photo: '/characters/diana.jpg', description: { es: 'Guiada por la compasión y la conexión humana ante todo.', en: 'Guided by compassion and human connection above all.', fr: 'Guidée par la compassion et la connexion humaine avant tout.', de: 'Geleitet von Mitgefühl und menschlicher Verbindung vor allem anderen.', it: 'Guidata dalla compassione e dalla connessione umana prima di tutto.', pt: 'Guiada pela compaixão e pela conexão humana acima de tudo.' }, philosophy: { es: 'Sientes profundamente el dolor ajeno y actúas desde el corazón. Tu brújula moral es la empatía, y crees que el mundo cambia una persona a la vez.', en: 'You deeply feel others\' pain and act from the heart. Your moral compass is empathy, and you believe the world changes one person at a time.', fr: 'Vous ressentez profondément la douleur des autres et agissez avec le cœur. Votre boussole morale est l\'empathie, et vous croyez que le monde change une personne à la fois.', de: 'Du fühlst den Schmerz anderer tief und handelst aus dem Herzen. Dein moralischer Kompass ist Empathie, und du glaubst, dass die Welt sich eine Person zur Zeit verändert.', it: 'Senti profondamente il dolore degli altri e agisci con il cuore. La tua bussola morale è l\'empatia, e credi che il mondo cambi una persona alla volta.', pt: 'Você sente profundamente a dor alheia e age com o coração. Sua bússola moral é a empatia, e você acredita que o mundo muda uma pessoa de cada vez.' } },
        { name: { es: 'Che Guevara', en: 'Che Guevara', fr: 'Che Guevara', de: 'Che Guevara', it: 'Che Guevara', pt: 'Che Guevara' }, dimensions: ['R'], photo: '/characters/che.jpg', description: { es: 'Rebelde que desafía el sistema cuando lo considera injusto.', en: 'Rebel who challenges the system when they consider it unjust.', fr: 'Rebelle qui défie le système lorsqu\'il le juge injuste.', de: 'Rebell, der das System herausfordert, wenn er es für ungerecht hält.', it: 'Ribelle che sfida il sistema quando lo considera ingiusto.', pt: 'Rebelde que desafia o sistema quando o considera injusto.' }, philosophy: { es: 'No aceptas el status quo cuando es injusto. Prefieres la acción directa sobre la diplomacia, y crees que el cambio real requiere valentía para enfrentar al sistema.', en: 'You do not accept the status quo when it is unjust. You prefer direct action over diplomacy, and believe real change requires courage to confront the system.', fr: 'Vous n\'acceptez pas le statu quo lorsqu\'il est injuste. Vous préférez l\'action directe à la diplomatie, et croyez que le vrai changement nécessite du courage pour affronter le système.', de: 'Du akzeptierst den Status quo nicht, wenn er ungerecht ist. Du bevorzugst direkte Aktion gegenüber Diplomatie und glaubst, dass echter Wandel Mut erfordert, das System zu konfrontieren.', it: 'Non accetti lo status quo quando è ingiusto. Preferisci l\'azione diretta alla diplomazia e credi che il vero cambiamento richieda coraggio per affrontare il sistema.', pt: 'Você não aceita o status quo quando é injusto. Prefere a ação direta à diplomacia e acredita que a mudança real requer coragem para enfrentar o sistema.' } },
        { name: { es: 'Nelson Mandela', en: 'Nelson Mandela', fr: 'Nelson Mandela', de: 'Nelson Mandela', it: 'Nelson Mandela', pt: 'Nelson Mandela' }, dimensions: ['P', 'I'], photo: '/characters/mandela.jpg', description: { es: 'Combina visión pragmática con principios inquebrantables.', en: 'Combines pragmatic vision with unbreakable principles.', fr: 'Combine vision pragmatique avec des principes inébranlables.', de: 'Kombiniert pragmatische Vision mit unerschütterlichen Prinzipien.', it: 'Combina visione pragmatica con principi incrollabili.', pt: 'Combina visão pragmática com princípios inquebráveis.' }, philosophy: { es: 'Sabes cuándo ser firme y cuándo ser flexible. Combinas la estrategia con la integridad, entendiendo que los grandes cambios requieren tanto paciencia como convicción.', en: 'You know when to be firm and when to be flexible. You combine strategy with integrity, understanding that great changes require both patience and conviction.', fr: 'Vous savez quand être ferme et quand être flexible. Vous combinez stratégie et intégrité, comprenant que les grands changements nécessitent à la fois de la patience et de la conviction.', de: 'Du weißt, wann du fest und wann du flexibel sein sollst. Du kombinierst Strategie mit Integrität und verstehst, dass große Veränderungen sowohl Geduld als auch Überzeugung erfordern.', it: 'Sai quando essere fermo e quando essere flessibile. Combini strategia con integrità, capendo che i grandi cambiamenti richiedono sia pazienza che convinzione.', pt: 'Você sabe quando ser firme e quando ser flexível. Combina estratégia com integridade, entendendo que grandes mudanças requerem tanto paciência quanto convicção.' } },
        { name: { es: 'Oprah Winfrey', en: 'Oprah Winfrey', fr: 'Oprah Winfrey', de: 'Oprah Winfrey', it: 'Oprah Winfrey', pt: 'Oprah Winfrey' }, dimensions: ['P', 'E'], photo: '/characters/oprah.jpg', description: { es: 'Pragmática pero siempre centrada en las personas.', en: 'Pragmatic but always focused on people.', fr: 'Pragmatique mais toujours centrée sur les personnes.', de: 'Pragmatisch, aber immer auf Menschen ausgerichtet.', it: 'Pragmatica ma sempre centrata sulle persone.', pt: 'Pragmática mas sempre centrada nas pessoas.' }, philosophy: { es: 'Eres efectivo/a y estratégico/a, pero nunca pierdes de vista a las personas. Crees que el éxito real viene de combinar inteligencia práctica con genuino interés por el bienestar de otros.', en: 'You are effective and strategic, but never lose sight of people. You believe real success comes from combining practical intelligence with genuine interest in the well-being of others.', fr: 'Vous êtes efficace et stratégique, mais ne perdez jamais les personnes de vue. Vous croyez que le vrai succès vient de combiner intelligence pratique avec un intérêt sincère pour le bien-être des autres.', de: 'Du bist effektiv und strategisch, verlierst aber nie die Menschen aus dem Blick. Du glaubst, dass echter Erfolg aus der Verbindung von praktischer Intelligenz mit echtem Interesse am Wohlergehen anderer kommt.', it: 'Sei efficace e strategico, ma non perdi mai di vista le persone. Credi che il vero successo venga dalla combinazione di intelligenza pratica con genuino interesse per il benessere degli altri.', pt: 'Você é eficaz e estratégico, mas nunca perde as pessoas de vista. Acredita que o sucesso real vem de combinar inteligência prática com interesse genuíno pelo bem-estar dos outros.' } },
        { name: { es: 'Martin Luther King Jr.', en: 'Martin Luther King Jr.', fr: 'Martin Luther King Jr.', de: 'Martin Luther King Jr.', it: 'Martin Luther King Jr.', pt: 'Martin Luther King Jr.' }, dimensions: ['I', 'R'], photo: '/characters/mlk.jpg', description: { es: 'Idealista que desafía lo establecido de forma pacífica.', en: 'Idealist who peacefully challenges the established order.', fr: 'Idéaliste qui défie l\'ordre établi de manière pacifique.', de: 'Idealist, der die etablierte Ordnung auf friedliche Weise herausfordert.', it: 'Idealista che sfida l\'ordine stabilito in modo pacifico.', pt: 'Idealista que desafia o estabelecido de forma pacífica.' }, philosophy: { es: 'Crees en un mundo mejor y estás dispuesto/a a luchar por él, pero desde los principios. Desafías la injusticia no con violencia, sino con la fuerza moral de tus convicciones.', en: 'You believe in a better world and are willing to fight for it, but from principles. You challenge injustice not with violence, but with the moral force of your convictions.', fr: 'Vous croyez en un monde meilleur et êtes prêt à vous battre pour lui, mais à partir de principes. Vous défiez l\'injustice non par la violence, mais par la force morale de vos convictions.', de: 'Du glaubst an eine bessere Welt und bist bereit, für sie zu kämpfen, aber aus Prinzipien heraus. Du bekämpfst Ungerechtigkeit nicht mit Gewalt, sondern mit der moralischen Kraft deiner Überzeugungen.', it: 'Credi in un mondo migliore e sei disposto a combatterci, ma partendo dai principi. Sfidi l\'ingiustizia non con la violenza, ma con la forza morale delle tue convinzioni.', pt: 'Você acredita em um mundo melhor e está disposto a lutar por ele, mas com princípios. Você desafia a injustiça não com violência, mas com a força moral de suas convicções.' } },
        { name: { es: 'Frida Kahlo', en: 'Frida Kahlo', fr: 'Frida Kahlo', de: 'Frida Kahlo', it: 'Frida Kahlo', pt: 'Frida Kahlo' }, dimensions: ['E', 'R'], photo: '/characters/frida.jpg', description: { es: 'Empática y auténtica, rompe moldes desde la vulnerabilidad.', en: 'Empathetic and authentic, breaks molds from vulnerability.', fr: 'Empathique et authentique, brise les moules depuis la vulnérabilité.', de: 'Einfühlsam und authentisch, bricht Formen aus der Verletzlichkeit heraus.', it: 'Empatica e autentica, rompe gli schemi dalla vulnerabilità.', pt: 'Empática e autêntica, quebra moldes desde a vulnerabilidade.' }, philosophy: { es: 'Tu sensibilidad es tu superpoder. Sientes profundamente y no temas mostrarlo, desafiando las normas desde la autenticidad. Crees que la vulnerabilidad es una forma de rebeldía.', en: 'Your sensitivity is your superpower. You feel deeply and are not afraid to show it, challenging norms from authenticity. You believe vulnerability is a form of rebellion.', fr: 'Votre sensibilité est votre superpouvoir. Vous ressentez profondément et n\'avez pas peur de le montrer, défiant les normes depuis l\'authenticité. Vous croyez que la vulnérabilité est une forme de rébellion.', de: 'Deine Sensibilität ist deine Superkraft. Du fühlst tief und hast keine Angst, es zu zeigen, und forderst Normen aus Authentizität heraus. Du glaubst, dass Verletzlichkeit eine Form der Rebellion ist.', it: 'La tua sensibilità è il tuo superpotere. Senti profondamente e non hai paura di mostrarlo, sfidando le norme dall\'autenticità. Credi che la vulnerabilità sia una forma di ribellione.', pt: 'Sua sensibilidade é seu superpoder. Você sente profundamente e não tem medo de mostrar, desafiando as normas desde a autenticidade. Você acredita que a vulnerabilidade é uma forma de rebeldia.' } },
      ],
    },
  });
}
